254→    (_event: MouseEvent | TouchEvent, params: { nodeId: string | null; handleId: string | null; handleType: "source" | "target" | null }) => {
255→      if (!params.nodeId || !params.handleId || !params.handleType) return;
256→      const currentEdges = useFlowStore.getState().edges;
257→      // Reconnect priority:
258→      // 1. Selected edge at this position (same pos, either source or target handle) → always reconnect
259→      //    Handles at the same position overlap visually, so user may grab the "wrong" one
260→      // 2. Exactly one edge on the dragged handle → reconnect it
261→      // 3. Multiple edges on handle + one selected → reconnect the selected one
262→      // 4. Otherwise → new connection mode
263→      const handlePos = params.handleId.split("-")[0]; // e.g. "bottom" from "bottom-source"
264→      const sourceHandleId = `${handlePos}-source`;
265→      const targetHandleId = `${handlePos}-target`;
266→
267→      // Priority 1: selected edge at this position (check both source and target handles)
268→      const selectedAtPos = currentEdges.find((e) => {
269→        if (!e.selected || e.data?.isBridgeEdge) return false;
270→        return (e.source === params.nodeId && e.sourceHandle === sourceHandleId) ||
271→               (e.target === params.nodeId && e.targetHandle === targetHandleId);
272→      });
