279→        // Determine which side of the edge connects to this node at this position
280→        actualReconnectType = (selectedAtPos.source === params.nodeId && selectedAtPos.sourceHandle === sourceHandleId)
281→          ? "source" : "target";
282→      } else {
283→        // Priority 2-3: fall back to edges on the exact dragged handle
284→        const edgesOnHandle = currentEdges.filter((e) => {
285→          if (e.data?.isBridgeEdge) return false;
286→          if (params.handleType === "source") return e.source === params.nodeId && e.sourceHandle === params.handleId;
287→          return e.target === params.nodeId && e.targetHandle === params.handleId;
