  3→import { useCallback, useMemo } from "react";
  4→import { useFlowStore } from "@/store/useFlowStore";
  5→import { computeCandidates } from "@/lib/predictive/candidateUtils";
  6→import { PREDICTIVE_GAP_PX, GHOST_NODE_ID, DEFAULT_NODE_WIDTH, DEFAULT_NODE_HEIGHT, DEFAULT_DIAMOND_SIZE } from "@/lib/constants";
  7→import type { PredictiveDirection, FlowNode, FlowEdge } from "@/store/types";
  8→import type { FlowNodeData } from "@/types/flow";
