 10→const GHOST_EDGE_ID = "__ghost_edge__";
 11→
 12→const DIRECTION_HANDLES: Record<PredictiveDirection, { sourceHandle: string; targetHandle: string }> = {
 13→  bottom: { sourceHandle: "bottom-source", targetHandle: "top-target" },
 14→  top:    { sourceHandle: "top-source",    targetHandle: "bottom-target" },
 15→  right:  { sourceHandle: "right-source",  targetHandle: "left-target" },
 16→  left:   { sourceHandle: "left-source",   targetHandle: "right-target" },
 17→};
 18→
 19→function getNodeSize(node: FlowNode): { w: number; h: number } {
 20→  const w = node.measured?.width ?? (node.style as Record<string, number>)?.width ?? DEFAULT_NODE_WIDTH;
 21→  const h = node.measured?.height ?? (node.style as Record<string, number>)?.height ?? DEFAULT_NODE_HEIGHT;
 22→  return { w, h };
 23→}
 24→
 25→function getDefaultSize(shape: string): { width: number; height: number } {
 26→  if (shape === "diamond") return { width: DEFAULT_DIAMOND_SIZE, height: DEFAULT_DIAMOND_SIZE };
 27→  if (shape === "circle") return { width: DEFAULT_NODE_HEIGHT * 2, height: DEFAULT_NODE_HEIGHT * 2 };
 28→  if (shape === "hexagon") return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT + 10 };
 29→  if (shape === "cylinder") return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT + 20 };
 30→  if (shape === "document") return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT + 10 };
 31→  if (shape === "predefinedProcess" || shape === "display") return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT };
 32→  return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT };
 33→}
 34→
 35→function computeGhostPosition(
 36→  sourceNode: FlowNode,
 37→  direction: PredictiveDirection,
 38→  ghostData: FlowNodeData,
 39→): { x: number; y: number } {
 40→  const { w: srcW, h: srcH } = getNodeSize(sourceNode);
 41→  const ghostSize = getDefaultSize(ghostData.shape);
 42→  const gw = ghostSize.width;
 43→  const gh = ghostSize.height;
 44→
 45→  switch (direction) {
 46→    case "bottom":
 47→      return { x: sourceNode.position.x + (srcW - gw) / 2, y: sourceNode.position.y + srcH + PREDICTIVE_GAP_PX };
 48→    case "top":
 49→      return { x: sourceNode.position.x + (srcW - gw) / 2, y: sourceNode.position.y - gh - PREDICTIVE_GAP_PX };
 50→    case "right":
 51→      return { x: sourceNode.position.x + srcW + PREDICTIVE_GAP_PX, y: sourceNode.position.y + (srcH - gh) / 2 };
 52→    case "left":
 53→      return { x: sourceNode.position.x - gw - PREDICTIVE_GAP_PX, y: sourceNode.position.y + (srcH - gh) / 2 };
 54→  }
 55→}
