136→  }, [clearPredictiveInput]);
137→
138→  const onCandidateCycle = useCallback((delta: number) => {
139→    if (!predictiveInput.ghostVisible || candidates.length === 0) return;
140→    const next = ((predictiveInput.candidateIndex + delta) % candidates.length + candidates.length) % candidates.length;
141→    setPredictiveInput({ candidateIndex: next });
142→  }, [predictiveInput.ghostVisible, predictiveInput.candidateIndex, candidates.length, setPredictiveInput]);
143→
144→  const onConfirm = useCallback(() => {
145→    if (!predictiveInput.sourceNodeId || !predictiveInput.direction || !currentCandidate || !ghostPosition) return;
146→
147→    const newId = addNodeWithData(currentCandidate.nodeData, ghostPosition);
148→    const handles = DIRECTION_HANDLES[predictiveInput.direction];
149→    addEdge(
150→      predictiveInput.sourceNodeId,
151→      newId,
152→      currentCandidate.edgeData?.label,
153→      handles.sourceHandle,
154→      handles.targetHandle,
155→      currentCandidate.edgeData,
156→    );
157→    clearPredictiveInput();
158→  }, [predictiveInput, currentCandidate, ghostPosition, addNodeWithData, addEdge, clearPredictiveInput]);
159→
160→  return {
161→    predictiveInput,
162→    ghostNode,
163→    ghostEdge,
164→    currentCandidate,
165→    candidates,
166→    onArrowEnter,
167→    onArrowLeave,
168→    onCandidateCycle,
169→    onConfirm,
170→    clearPredictiveInput,
171→  };
172→}
