 45→/**
 46→ * Compute predictive input candidates for a source node.
 47→ * Returns up to 4 candidates (duplicates by shape removed).
 48→ */
 49→export function computeCandidates(
 50→  sourceNode: FlowNode,
 51→  allEdges: FlowEdge[],
 52→  allNodes: FlowNode[],
 53→): PredictiveCandidate[] {
 54→  const candidates: PredictiveCandidate[] = [];
 55→  const seenShapes = new Set<NodeShape>();
 56→
 57→  const srcData = sourceNode.data;
 58→
 59→  // Find an existing edge from this source to derive edge style
 60→  const outEdge = allEdges.find(
 61→    (e) => e.source === sourceNode.id && !e.data?.isBridgeEdge,
 62→  );
 63→  const outEdgeData: Partial<FlowEdgeData> = outEdge?.data
 64→    ? {
 65→        edgeType: outEdge.data.edgeType,
 66→        markerStart: outEdge.data.markerStart,
 67→        markerEnd: outEdge.data.markerEnd,
 68→        strokeWidth: outEdge.data.strokeWidth,
 69→        strokeColor: outEdge.data.strokeColor,
 70→        strokeStyle: outEdge.data.strokeStyle,
 71→      }
 72→    : {};
 73→
 74→  // 1. Full copy (style + label)
 75→  const fullCopyData: FlowNodeData = {
 76→    label: "",  // will be replaced with new ID
 77→    shape: srcData.shape,
 78→    ...(srcData.fillColor && { fillColor: srcData.fillColor }),
 79→    ...(srcData.fillOpacity !== undefined && { fillOpacity: srcData.fillOpacity }),
 80→    ...(srcData.fillLightness !== undefined && { fillLightness: srcData.fillLightness }),
 81→    ...(srcData.borderColor && { borderColor: srcData.borderColor }),
 82→    ...(srcData.borderOpacity !== undefined && { borderOpacity: srcData.borderOpacity }),
 83→    ...(srcData.borderLightness !== undefined && { borderLightness: srcData.borderLightness }),
 84→    ...(srcData.borderWidth && { borderWidth: srcData.borderWidth }),
 85→    ...(srcData.borderStyle && { borderStyle: srcData.borderStyle }),
 86→    ...(srcData.fontSize && { fontSize: srcData.fontSize }),
 87→    ...(srcData.textColor && { textColor: srcData.textColor }),
 88→    ...(srcData.textOpacity !== undefined && { textOpacity: srcData.textOpacity }),
 89→    ...(srcData.textLightness !== undefined && { textLightness: srcData.textLightness }),
 90→    ...(srcData.textAlign && { textAlign: srcData.textAlign }),
 91→    ...(srcData.bold && { bold: srcData.bold }),
 92→    ...(srcData.italic && { italic: srcData.italic }),
 93→    ...(srcData.underline && { underline: srcData.underline }),
 94→  };
 95→  candidates.push({ kind: "fullCopy", nodeData: fullCopyData, edgeData: outEdgeData });
 96→  seenShapes.add(srcData.shape);
 97→
 98→  // 2. Shape only copy (skip if source has no custom style — would be identical to fullCopy)
 99→  const hasCustomStyle = !!(
100→    srcData.fillColor || srcData.fillOpacity !== undefined || srcData.fillLightness !== undefined ||
101→    srcData.borderColor || srcData.borderOpacity !== undefined || srcData.borderLightness !== undefined ||
102→    srcData.borderWidth || srcData.borderStyle ||
103→    srcData.fontSize || srcData.textColor || srcData.textOpacity !== undefined || srcData.textLightness !== undefined ||
104→    srcData.textAlign || srcData.bold || srcData.italic || srcData.underline
105→  );
106→  if (hasCustomStyle) {
107→    const shapeCopyData: FlowNodeData = {
108→      label: "",
109→      shape: srcData.shape,
110→    };
111→    candidates.push({ kind: "shapeCopy", nodeData: shapeCopyData, edgeData: {} });
112→  }
113→
114→  // 3-4. Pair frequency candidates
115→  const pairShapes = computePairFrequencies(srcData.shape, allEdges, allNodes);
116→  for (let i = 0; i < pairShapes.length && candidates.length < 4; i++) {
117→    const shape = pairShapes[i];
118→    if (seenShapes.has(shape)) continue;
119→    seenShapes.add(shape);
120→    const kind = candidates.length === 2 ? "pairFreq1" as const : "pairFreq2" as const;
121→    candidates.push({
122→      kind,
123→      nodeData: { label: "", shape },
124→      edgeData: {},
125→    });
126→  }
127→
128→  // Fill with rectangle (処理) if not yet at 4 candidates
129→  if (candidates.length < 4 && !seenShapes.has("rectangle")) {
130→    candidates.push({ kind: "pairFreq1", nodeData: { label: "", shape: "rectangle" }, edgeData: {} });
131→    seenShapes.add("rectangle");
132→  }
133→
134→  // Fill with diamond (条件分岐) if not yet at 4 candidates
135→  if (candidates.length < 4 && !seenShapes.has("diamond")) {
136→    candidates.push({ kind: "pairFreq2", nodeData: { label: "", shape: "diamond" }, edgeData: {} });
137→  }
138→
139→  return candidates;
140→}
141→
142→/**
143→ * Count edge pairs where source shape matches, return target shapes sorted by frequency.
144→ * Excludes "text" shape from results.
145→ */
146→function computePairFrequencies(
147→  sourceShape: NodeShape,
148→  allEdges: FlowEdge[],
149→  allNodes: FlowNode[],
150→): NodeShape[] {
151→  const nodeMap = new Map<string, FlowNode>();
152→  for (const n of allNodes) nodeMap.set(n.id, n);
153→
154→  const freq = new Map<NodeShape, number>();
155→  for (const edge of allEdges) {
156→    if (edge.data?.isBridgeEdge) continue;
157→    const src = nodeMap.get(edge.source);
158→    const tgt = nodeMap.get(edge.target);
159→    if (!src || !tgt) continue;
160→    if (src.data.shape !== sourceShape) continue;
161→    if (tgt.data.shape === "text") continue;
162→    freq.set(tgt.data.shape, (freq.get(tgt.data.shape) ?? 0) + 1);
163→  }
164→
165→  return [...freq.entries()]
166→    .sort((a, b) => b[1] - a[1])
167→    .map(([shape]) => shape);
168→}
