129→export function calculateComponentSize(def: ComponentDefinition): { width: number; height: number } {
130→  // Exclude entry/exit nodes from size calculation
131→  const excludeIds = new Set<string>();
132→  if (def.entryNodeId) excludeIds.add(def.entryNodeId);
133→  if (def.exitNodeId) excludeIds.add(def.exitNodeId);
134→
135→  const sizeNodes = def.nodes.filter((n) => !excludeIds.has(n.id));
136→  const sMinX = sizeNodes.length > 0 ? Math.min(...sizeNodes.map((n) => n.position.x)) : 0;
137→  const sMinY = sizeNodes.length > 0 ? Math.min(...sizeNodes.map((n) => n.position.y)) : 0;
138→
139→  let maxX = 0;
140→  let maxY = 0;
141→  for (const n of sizeNodes) {
142→    const right = (n.position.x - sMinX + (n.style?.width ?? CHILD_NODE_W)) * CHILD_SCALE;
143→    const bottom = (n.position.y - sMinY + (n.style?.height ?? CHILD_NODE_H)) * CHILD_SCALE;
144→    if (right > maxX) maxX = right;
145→    if (bottom > maxY) maxY = bottom;
146→  }
147→  return {
148→    width: Math.max(200, Math.round(maxX) + COMPONENT_PADDING * 2),
149→    height: Math.max(120, Math.round(maxY) + COMPONENT_HEADER_HEIGHT + COMPONENT_PADDING * 2),
150→  };
151→}
