153→/**
154→ * Recompute child node positions and sizes from the definition's base layout,
155→ * scaled to fit the current parent content area. This avoids compound scaling errors.
156→ */
157→export function rescaleComponentChildren(
158→  childNodes: FlowNode[],
159→  parentId: string,
160→  def: ComponentDefinition,
161→  parentW: number,
162→  parentH: number,
163→): FlowNode[] {
164→  const baseSize = calculateComponentSize(def);
165→  const baseContentW = baseSize.width - COMPONENT_PADDING * 2;
166→  const baseContentH = baseSize.height - COMPONENT_HEADER_HEIGHT - COMPONENT_PADDING * 2;
167→  const currentContentW = parentW - COMPONENT_PADDING * 2;
168→  const currentContentH = parentH - COMPONENT_HEADER_HEIGHT - COMPONENT_PADDING * 2;
169→  if (baseContentW <= 0 || baseContentH <= 0 || currentContentW <= 0 || currentContentH <= 0) return childNodes;
170→
171→  const scale = Math.min(currentContentW / baseContentW, currentContentH / baseContentH);
172→
173→  // Exclude entry/exit nodes from the definition (same logic as generateComponentChildren)
174→  const excludeIds = new Set<string>();
175→  if (def.entryNodeId) excludeIds.add(def.entryNodeId);
176→  if (def.exitNodeId) excludeIds.add(def.exitNodeId);
177→  const visibleNodes = def.nodes.filter((n) => !excludeIds.has(n.id));
178→  const minX = visibleNodes.length > 0 ? Math.min(...visibleNodes.map((n) => n.position.x)) : 0;
179→  const minY = visibleNodes.length > 0 ? Math.min(...visibleNodes.map((n) => n.position.y)) : 0;
180→
181→  // Build a map from definition node id → base position/size
182→  const baseMap = new Map<string, { x: number; y: number; w: number; h: number }>();
183→  for (const n of visibleNodes) {
184→    baseMap.set(n.id, {
185→      x: (n.position.x - minX) * CHILD_SCALE,
186→      y: (n.position.y - minY) * CHILD_SCALE,
187→      w: (n.style?.width ?? CHILD_NODE_W) * CHILD_SCALE,
188→      h: (n.style?.height ?? CHILD_NODE_H) * CHILD_SCALE,
189→    });
190→  }
191→
192→  return childNodes.map((child) => {
193→    if (child.data.componentParentId !== parentId) return child;
194→    const internalId = child.data.componentInternalId as string | undefined;
195→    if (!internalId) return child;
196→    const base = baseMap.get(internalId);
197→    if (!base) return child;
198→
199→    return {
200→      ...child,
201→      position: {
202→        x: COMPONENT_PADDING + base.x * scale,
203→        y: COMPONENT_HEADER_HEIGHT + COMPONENT_PADDING + base.y * scale,
204→      },
205→      style: {
206→        ...child.style,
207→        width: Math.max(MIN_CHILD_W, Math.round(base.w * scale)),
208→        height: Math.max(MIN_CHILD_H, Math.round(base.h * scale)),
209→      },
210→    };
211→  });
212→}
