 3→/**
 4→ * Escape special characters for Mermaid syntax using #<charcode>; format
 5→ */
 6→export function escapeMermaid(text: string): string {
 7→  return text
 8→    .replace(/&/g, "#amp;")
 9→    .replace(/"/g, "#quot;")
10→    .replace(/</g, "#lt;")
11→    .replace(/>/g, "#gt;")
12→    .replace(/{/g, "#lbrace;")
13→    .replace(/}/g, "#rbrace;")
14→    .replace(/\(/g, "#lpar;")
15→    .replace(/\)/g, "#rpar;")
16→    .replace(/\[/g, "#lbrack;")
17→    .replace(/]/g, "#rbrack;");
18→}
