20→/**
21→ * Convert a node to Mermaid syntax based on shape
22→ */
23→export function nodeToMermaid(node: FlowNode): string {
24→  const id = node.id;
25→  const label = escapeMermaid(node.data.label);
26→  const shape = node.data.shape;
27→
28→  switch (shape) {
29→    case "rectangle":
30→      return `    ${id}[${label}]`;
31→    case "diamond":
32→      return `    ${id}{${label}}`;
33→    case "roundedRect":
34→      return `    ${id}(${label})`;
35→    case "circle":
36→      return `    ${id}((${label}))`;
37→    case "parallelogram":
38→      return `    ${id}[/${label}/]`;
39→    case "cylinder":
40→      return `    ${id}[(${label})]`;
41→    case "hexagon":
42→      return `    ${id}{{${label}}}`;
43→    case "stadium":
44→      return `    ${id}([${label}])`;
45→    case "trapezoid":
46→      return `    ${id}[\\${label}\\]`;
47→    case "document":
48→      return `    ${id}[/${label}\\]`;
49→    case "predefinedProcess":
50→      return `    ${id}[[${label}]]`;
51→    case "manualInput":
52→      return `    ${id}[\\${label}/]`;
53→    case "internalStorage":
54→      return `    ${id}[${label}]`;
55→    case "display":
56→      return `    ${id}(${label})`;
57→    default:
58→      return `    ${id}[${label}]`;
59→  }
60→}
