 14→export function unescapeMermaid(text: string): string {
 15→  return text
 16→    .replace(/#amp;/g, "&")
 17→    .replace(/#quot;/g, '"')
 18→    .replace(/#lt;/g, "<")
 19→    .replace(/#gt;/g, ">")
 20→    .replace(/#lbrace;/g, "{")
 21→    .replace(/#rbrace;/g, "}")
 22→    .replace(/#lpar;/g, "(")
 23→    .replace(/#rpar;/g, ")")
 24→    .replace(/#lbrack;/g, "[")
 25→    .replace(/#rbrack;/g, "]");
 26→}
