      const selectedNodeIds = nodes.filter((n) => n.selected).map((n) => n.id);
      const ids = selectedNodeIds.includes(node.id) ? selectedNodeIds : [node.id];
      openMenu(event as unknown as React.MouseEvent, ids, []);
    },
    [nodes, openMenu]
