                  <div>{t("helpCtrlA")}</div>
                  <div>{t("helpCtrlC")}</div>
                  <div>{t("helpCtrlZ")}</div>
                  <div>{t("helpDelete")}</div>
                </div>
              </div>
            </div>
          </div>
        </Panel>
