  // ----------------------------------------------------------
  describe("パターン11: ゴーストエッジ（予測入力）", () => {
    it("ゴーストエッジの期待構造: トップレベル markerEnd が必要", () => {
      // ゴーストエッジの生成パターンを再現
      // FlowCanvas.tsx:187-202 と usePredictiveInput.ts:100-123 の構造
      const ghostEdge = {
        id: "__ghost_edge__test",
        source: "A",
        target: "__ghost__A_bottom",
        sourceHandle: "bottom-source",
        targetHandle: "top-target",
