242→export const LabeledEdge = memo(function LabeledEdge({
243→  id,
244→  source,
245→  target,
246→  sourceX,
247→  sourceY,
248→  targetX,
249→  targetY,
250→  sourcePosition,
251→  targetPosition,
252→  style,
253→  data,
254→  selected,
255→  markerEnd,
256→  markerStart,
257→}: EdgeProps<FlowEdge>) {
258→  perfCount("LabeledEdge");
259→  const edgeType = data?.edgeType ?? "bezier";
260→  const waypoints = data?.waypoints ?? [];
261→  const hasWaypoints = waypoints.length > 0;
262→
263→  const pathParams = { sourceX, sourceY, sourcePosition, targetX, targetY, targetPosition };
264→  let edgePath: string;
265→  let labelX: number;
266→  let labelY: number;
267→
268→  if (hasWaypoints) {
269→    edgePath = buildWaypointPath(sourceX, sourceY, targetX, targetY, waypoints);
270→    const allPts: Waypoint[] = [{ x: sourceX, y: sourceY }, ...waypoints, { x: targetX, y: targetY }];
271→    const midSegIdx = Math.floor((allPts.length - 1) / 2);
272→    const a = allPts[midSegIdx];
273→    const b = allPts[midSegIdx + 1];
274→    labelX = (a.x + b.x) / 2;
275→    labelY = (a.y + b.y) / 2 - 16;
276→  } else if (edgeType === "straight") {
277→    [edgePath, labelX, labelY] = getStraightPath(pathParams);
278→  } else if (edgeType === "step") {
279→    [edgePath, labelX, labelY] = getSmoothStepPath({ ...pathParams, borderRadius: 8 });
280→  } else {
281→    [edgePath, labelX, labelY] = getBezierPath(pathParams);
282→  }
283→
284→  const updateEdgeWaypoints = useFlowStore((s) => s.updateEdgeWaypoints);
285→
286→  // Auto-generate waypoints when switching to step with no existing waypoints
287→  const prevEdgeTypeRef = useRef(edgeType);
288→  useEffect(() => {
289→    if (edgeType === "step" && prevEdgeTypeRef.current !== "step" && waypoints.length === 0) {
290→      const corners = computeStepCornersAvoidingNodes(sourceX, sourceY, sourcePosition, targetX, targetY, targetPosition, source, target);
291→      if (corners.length > 0) {
292→        updateEdgeWaypoints(id, corners);
293→      }
294→    }
295→    prevEdgeTypeRef.current = edgeType;
296→  }, [edgeType]); // eslint-disable-line react-hooks/exhaustive-deps
297→
298→  // Track node movement and adjust waypoints to maintain right-angle segments
299→  const prevPosRef = useRef({ sx: sourceX, sy: sourceY, tx: targetX, ty: targetY });
300→  useEffect(() => {
301→    const prev = prevPosRef.current;
302→    const sdx = sourceX - prev.sx;
303→    const sdy = sourceY - prev.sy;
304→    const tdx = targetX - prev.tx;
305→    const tdy = targetY - prev.ty;
306→    prevPosRef.current = { sx: sourceX, sy: sourceY, tx: targetX, ty: targetY };
307→
308→    if ((sdx === 0 && sdy === 0 && tdx === 0 && tdy === 0) || waypoints.length === 0) return;
309→
310→    if (waypoints.length <= 2) {
311→      // Basic step edge (auto-generated): recalculate from scratch to avoid broken paths
312→      const corners = computeStepCornersAvoidingNodes(sourceX, sourceY, sourcePosition, targetX, targetY, targetPosition, source, target);
313→      if (corners.length === 0) {
314→        // Nodes are aligned — clear waypoints
315→        updateEdgeWaypoints(id, []);
316→        return;
317→      }
318→      if (corners.every((w, i) => waypoints[i] && w.x === waypoints[i].x && w.y === waypoints[i].y)) return;
319→      updateEdgeWaypoints(id, corners);
320→    } else {
321→      // User-customized step edge (3+ waypoints from double-click): delta-based adjustment
322→      const updated = waypoints.map(w => ({ ...w }));
323→      const wp0 = updated[0];
324→      const wpLast = updated[updated.length - 1];
325→
326→      const firstIsVertical = Math.abs(prev.sx - wp0.x) <= Math.abs(prev.sy - wp0.y);
327→
328→      if (firstIsVertical) {
329→        wp0.x = Math.round(sourceX);
330→        wpLast.x = Math.round(targetX);
331→        const midY = computeMid(sourceY, targetY, sourcePosition, targetPosition, Position.Bottom);
332→        wp0.y = midY;
333→        wpLast.y = midY;
334→      } else {
335→        wp0.y = Math.round(sourceY);
336→        wpLast.y = Math.round(targetY);
337→        const midX = computeMid(sourceX, targetX, sourcePosition, targetPosition, Position.Right);
338→        wp0.x = midX;
339→        wpLast.x = midX;
340→      }
341→
342→      for (let i = 1; i < updated.length - 1; i++) {
343→        updated[i].x += Math.round((sdx + tdx) / 2);
344→        updated[i].y += Math.round((sdy + tdy) / 2);
345→      }
346→
347→      if (updated.every((w, i) => w.x === waypoints[i].x && w.y === waypoints[i].y)) return;
348→      updateEdgeWaypoints(id, updated);
349→    }
350→  }, [sourceX, sourceY, targetX, targetY]); // eslint-disable-line react-hooks/exhaustive-deps
351→
352→  const label = data?.label ?? "";
353→  const [editing, setEditing] = useState(false);
354→  const [value, setValue] = useState(label);
355→  const inputRef = useRef<HTMLInputElement>(null);
356→  const updateEdgeLabel = useFlowStore((s) => s.updateEdgeLabel);
357→  const { screenToFlowPosition } = useReactFlow();
358→
359→  useEffect(() => {
360→    setValue(label);
361→  }, [label]);
362→
363→  useEffect(() => {
364→    if (editing) {
365→      inputRef.current?.focus();
366→      inputRef.current?.select();
367→    }
368→  }, [editing]);
369→
370→  const commit = useCallback(() => {
371→    setEditing(false);
372→    updateEdgeLabel(id, value.trim());
373→  }, [id, value, updateEdgeLabel]);
374→
375→  const strokeColor = computeColor(data?.strokeColor, data?.strokeOpacity, data?.strokeLightness) ?? undefined;
376→  const strokeWidth = data?.strokeWidth ?? 2;
377→
378→  // Double-click on step edge: add a new jog (2 waypoints) at clicked segment
379→  const handleEdgeDoubleClick = useCallback(
380→    (e: React.MouseEvent) => {
381→      if (edgeType !== "step") return;
382→      e.stopPropagation();
383→      const pos = screenToFlowPosition({ x: e.clientX, y: e.clientY });
384→      const clickPt: Waypoint = { x: Math.round(pos.x), y: Math.round(pos.y) };
385→      const allPts: Waypoint[] = [{ x: sourceX, y: sourceY }, ...waypoints, { x: targetX, y: targetY }];
386→      const segIdx = findClosestSegment(allPts, clickPt);
387→
388→      const a = allPts[segIdx];
389→      const b = allPts[segIdx + 1];
390→      const isHorizontal = Math.abs(a.y - b.y) < Math.abs(a.x - b.x);
391→
392→      // Insert 2 new waypoints to create a jog perpendicular to the segment
393→      let newWp1: Waypoint;
394→      let newWp2: Waypoint;
395→      if (isHorizontal) {
396→        // Horizontal segment → add vertical jog
397→        newWp1 = { x: clickPt.x, y: a.y };
398→        newWp2 = { x: clickPt.x, y: clickPt.y };
399→      } else {
400→        // Vertical segment → add horizontal jog
401→        newWp1 = { x: a.x, y: clickPt.y };
402→        newWp2 = { x: clickPt.x, y: clickPt.y };
403→      }
404→
405→      const updated = [...waypoints];
406→      // segIdx maps to waypoint insertion: waypoint index = segIdx (since allPts[0] is source)
407→      updated.splice(segIdx, 0, newWp1, newWp2);
408→      updateEdgeWaypoints(id, updated);
409→    },
410→    [id, edgeType, waypoints, sourceX, sourceY, targetX, targetY, screenToFlowPosition, updateEdgeWaypoints]
411→  );
412→
413→  // Build segments for drag handles
414→  const allPts: Waypoint[] = hasWaypoints
415→    ? [{ x: sourceX, y: sourceY }, ...waypoints, { x: targetX, y: targetY }]
416→    : [];
417→
418→  return (
419→    <>
420→      {/* Invisible wider path for easier clicking/double-clicking */}
421→      <path
422→        d={edgePath}
423→        fill="none"
424→        stroke="transparent"
425→        strokeWidth={Math.max(strokeWidth, 2) + 16}
426→        onDoubleClick={(e) => {
427→          if (edgeType === "step") {
428→            handleEdgeDoubleClick(e);
429→          } else {
430→            e.stopPropagation();
431→            setEditing(true);
432→          }
433→        }}
434→        style={{ cursor: edgeType === "step" ? "crosshair" : undefined }}
435→      />
436→      {/* Selection glow (like node box-shadow) */}
437→      {selected && (
438→        <path
439→          d={edgePath}
440→          fill="none"
441→          stroke="var(--primary)"
442→          strokeWidth={strokeWidth + 10}
443→          strokeOpacity={0.4}
444→          strokeLinecap="round"
445→          strokeLinejoin="round"
446→          style={{ pointerEvents: "none" }}
447→        />
448→      )}
449→      <path
450→        d={edgePath}
451→        fill="none"
452→        strokeWidth={strokeWidth}
453→        markerEnd={markerEnd as string}
454→        markerStart={markerStart as string}
455→        style={{
456→          ...style,
457→          ...(strokeColor && { stroke: strokeColor }),
458→          strokeDasharray:
459→            data?.strokeStyle === "dashed" ? "8 4" :
460→            data?.strokeStyle === "dotted" ? "2 2" :
461→            undefined,
462→        }}
463→        className="react-flow__edge-path"
464→      />
465→      {/* Segment drag handles (only when selected, step edges with waypoints) */}
466→      {selected && hasWaypoints && allPts.map((_, segIdx) => {
467→        if (segIdx >= allPts.length - 1) return null;
468→        // Only middle segments (both endpoints are waypoints)
469→        const startIsWp = segIdx > 0;
470→        const endIsWp = segIdx + 1 < allPts.length - 1;
471→        if (!startIsWp || !endIsWp) return null;
472→        const p1 = allPts[segIdx];
473→        const p2 = allPts[segIdx + 1];
474→        return (
475→          <SegmentHandle
476→            key={segIdx}
477→            segIdx={segIdx}
478→            p1={p1}
479→            p2={p2}
480→            edgeId={id}
481→            waypoints={waypoints}
482→            updateEdgeWaypoints={updateEdgeWaypoints}
483→            screenToFlowPosition={screenToFlowPosition}
484→          />
485→        );
486→      })}
487→      <EdgeLabelRenderer>
488→        {(editing || label !== "") ? (
489→          <div
490→            className="nodrag nopan absolute bg-background border border-border rounded px-1 text-xs"
491→            style={{
492→              transform: `translate(-50%, -50%) translate(${labelX}px,${labelY}px)`,
493→              pointerEvents: "all",
494→              cursor: "pointer",
495→            }}
496→            onDoubleClick={(e) => {
497→              e.stopPropagation();
498→              setEditing(true);
499→            }}
500→          >
501→            {editing ? (
502→              <input
503→                ref={inputRef}
504→                className="bg-transparent text-center text-xs outline-none w-16"
505→                value={value}
506→                onChange={(e) => setValue(e.target.value)}
507→                onBlur={commit}
508→                onKeyDown={(e) => {
509→                  if (e.key === "Enter") commit();
510→                  if (e.key === "Escape") {
511→                    setValue(label);
512→                    setEditing(false);
513→                  }
514→                }}
515→              />
516→            ) : (
517→              <span>{label}</span>
518→            )}
519→          </div>
520→        ) : selected ? (
521→          <div
522→            className="nodrag nopan absolute rounded text-xs"
523→            style={{
524→              transform: `translate(-50%, -50%) translate(${labelX}px,${labelY}px)`,
525→              pointerEvents: "all",
526→              cursor: "pointer",
527→              border: "1px dashed var(--border)",
528→              opacity: 0.6,
529→              padding: "0 4px",
530→              color: "var(--muted-foreground)",
531→            }}
532→            onDoubleClick={(e) => {
533→              e.stopPropagation();
534→              setEditing(true);
535→            }}
536→          >
537→            +
538→          </div>
539→        ) : null}
540→      </EdgeLabelRenderer>
541→    </>
542→  );
543→});
