545→function SegmentHandle({
546→  segIdx,
547→  p1,
548→  p2,
549→  edgeId,
550→  waypoints,
551→  updateEdgeWaypoints,
552→  screenToFlowPosition,
553→}: {
554→  segIdx: number;
555→  p1: Waypoint;
556→  p2: Waypoint;
557→  edgeId: string;
558→  waypoints: Waypoint[];
559→  updateEdgeWaypoints: (id: string, wps: Waypoint[]) => void;
560→  screenToFlowPosition: (pos: { x: number; y: number }) => { x: number; y: number };
561→}) {
562→  const [hovered, setHovered] = useState(false);
563→  const [dragging, setDragging] = useState(false);
564→  const isHorizontal = Math.abs(p1.y - p2.y) < Math.abs(p1.x - p2.x);
565→  const mx = (p1.x + p2.x) / 2;
566→  const my = (p1.y + p2.y) / 2;
567→  const cursor = isHorizontal ? "ns-resize" : "ew-resize";
568→
569→  // Both endpoints are always waypoints (middle segment)
570→  const wpStartIdx = segIdx - 1;
571→  const wpEndIdx = segIdx;
572→
573→  const handlePointerDown = useCallback((e: React.PointerEvent) => {
574→    e.stopPropagation();
575→    e.preventDefault();
576→    setDragging(true);
577→    (e.currentTarget as Element).setPointerCapture(e.pointerId);
578→  }, []);
579→
580→  const handlePointerMove = useCallback((e: React.PointerEvent) => {
581→    if (!dragging) return;
582→    const pos = screenToFlowPosition({ x: e.clientX, y: e.clientY });
583→    const updated = waypoints.map(w => ({ ...w }));
584→
585→    if (isHorizontal) {
586→      const newY = Math.round(pos.y);
587→      if (wpStartIdx >= 0 && wpStartIdx < updated.length) updated[wpStartIdx].y = newY;
588→      if (wpEndIdx >= 0 && wpEndIdx < updated.length) updated[wpEndIdx].y = newY;
589→    } else {
590→      const newX = Math.round(pos.x);
591→      if (wpStartIdx >= 0 && wpStartIdx < updated.length) updated[wpStartIdx].x = newX;
592→      if (wpEndIdx >= 0 && wpEndIdx < updated.length) updated[wpEndIdx].x = newX;
593→    }
594→
595→    updateEdgeWaypoints(edgeId, updated);
596→  }, [dragging, isHorizontal, wpStartIdx, wpEndIdx, edgeId, waypoints, screenToFlowPosition, updateEdgeWaypoints]);
597→
598→  const handlePointerUp = useCallback(() => {
599→    setDragging(false);
600→    setHovered(false);
601→  }, []);
602→
603→  const segLen = Math.hypot(p2.x - p1.x, p2.y - p1.y);
604→  if (segLen < 5) return null;
605→
606→  const showIcon = hovered || dragging;
607→
608→  return (
609→    <>
610→      {/* Invisible wider hit area */}
611→      <line
612→        x1={p1.x} y1={p1.y}
613→        x2={p2.x} y2={p2.y}
614→        stroke="transparent"
615→        strokeWidth={16}
616→        style={{ cursor, pointerEvents: "all" }}
617→        onPointerEnter={() => setHovered(true)}
618→        onPointerLeave={() => { if (!dragging) setHovered(false); }}
619→        onPointerDown={handlePointerDown}
620→        onPointerMove={handlePointerMove}
621→        onPointerUp={handlePointerUp}
622→      />
623→      {/* Grab indicator at midpoint — only on hover */}
624→      {showIcon && (
625→        isHorizontal ? (
626→          <g style={{ pointerEvents: "none" }}>
627→            <line x1={mx - 6} y1={my - 3} x2={mx + 6} y2={my - 3} stroke="var(--handle-color)" strokeWidth={1.5} strokeLinecap="round" />
628→            <line x1={mx - 6} y1={my} x2={mx + 6} y2={my} stroke="var(--handle-color)" strokeWidth={1.5} strokeLinecap="round" />
629→            <line x1={mx - 6} y1={my + 3} x2={mx + 6} y2={my + 3} stroke="var(--handle-color)" strokeWidth={1.5} strokeLinecap="round" />
630→          </g>
631→        ) : (
632→          <g style={{ pointerEvents: "none" }}>
633→            <line x1={mx - 3} y1={my - 6} x2={mx - 3} y2={my + 6} stroke="var(--handle-color)" strokeWidth={1.5} strokeLinecap="round" />
634→            <line x1={mx} y1={my - 6} x2={mx} y2={my + 6} stroke="var(--handle-color)" strokeWidth={1.5} strokeLinecap="round" />
635→            <line x1={mx + 3} y1={my - 6} x2={mx + 3} y2={my + 6} stroke="var(--handle-color)" strokeWidth={1.5} strokeLinecap="round" />
636→          </g>
637→        )
638→      )}
639→    </>
640→  );
641→}
