 10→// ============================================================
 11→// Helper: markerEnd がトップレベルに設定されているかを検証
 12→// ============================================================
 13→function expectMarkerEnd(edge: FlowEdge, expectedType: MarkerType = MarkerType.ArrowClosed) {
 14→  expect(edge.markerEnd).toBeDefined();
 15→  expect(edge.markerEnd).toHaveProperty("type", expectedType);
 16→}
 17→
 18→function expectDataMarkerEnd(edge: FlowEdge, expectedValue: MarkerStyle = "arrowclosed") {
 19→  expect(edge.data?.markerEnd).toBe(expectedValue);
 20→}
