 25→function addTestNodes(...ids: string[]) {
 26→  const store = useFlowStore.getState();
 27→  for (const id of ids) {
 28→    store.addNode(id, "rectangle", { x: 100, y: 100 });
 29→  }
 30→}
 31→
 32→function getEdge(id?: string): FlowEdge {
 33→  const edges = useFlowStore.getState().edges;
 34→  if (id) return edges.find((e) => e.id === id)!;
 35→  // 非ブリッジエッジの最初の1つを返す
 36→  return edges.filter((e) => !e.data?.isBridgeEdge)[0];
 37→}
 38→
 39→function getNonBridgeEdges(): FlowEdge[] {
 40→  return useFlowStore.getState().edges.filter((e) => !e.data?.isBridgeEdge);
 41→}
